+                    ).join('\n');
+                    output.innerHTML += `<pre>${conflictList}</pre>`;
+                }
+            } catch (error) {
+                log(`Error: ${error.message || error}`, 'error');
+            }
+        });
+
+        btnClear.addEventListener('click', () => {
+            output.innerHTML = '';
+            log('Output cleared');
+        });
+    </script>
