+            id: self.id.unwrap_or_default(),
+            change_id: self.change_id.unwrap_or_default(),
+            message: self.message.unwrap_or_default(),
+            author: self.author.unwrap_or_default(),
+            author_email: self.author_email.unwrap_or_default(),
